#include <iostream>
#include <vector>
#include <cmath> 

// Assuming the Temperature class definition is available here

void run_test(double input_celsius, double expected_fahrenheit) {
    Temperature temp(input_celsius);
    double actual_fahrenheit = temp.getFahrenheit();
    bool passed = std::abs(actual_fahrenheit - expected_fahrenheit) < 0.001;

    std::cout << "Input Celsius: " << input_celsius
              << ", Expected Fahrenheit: " << expected_fahrenheit
              << ", Actual Fahrenheit: " << actual_fahrenheit
              << (passed ? " (PASSED)" : " (FAILED)") << std::endl;
}

int main() {
    run_test(0.0, 32.0);
    run_test(100.0, 212.0);
    run_test(25.0, 77.0);
    return 0;
}
